class Solution(object):
    def numOfUnplacedFruits(self, fruits, baskets):
        used = [False] * len(baskets)
        unplaced = 0
        for fruit in fruits:
            placed = False
            for j, cap in enumerate(baskets):
                if not used[j] and cap > fruit:
                    used[j] = True
                    placed = True
                    break
            if not placed:
                unplaced += 1
        return unplaced
